mapper.select:
SELECT user_key, kakao_api_id, nickname, created_at, referrer_url, system_role FROM `user`
(LOWER(nickname) LIKE CONCAT('%', LOWER(#{q}), '%') OR LOWER(referrer_url) LIKE CONCAT('%', LOWER(#{q}), '%'))
ORDER BY user_key DESC LIMIT #{size} OFFSET #{offset}

SELECT group_id AS groupId, name, leader_user_key AS leaderUserKey, description, capacity, created_at FROM `group`
LOWER(name) LIKE CONCAT('%', LOWER(#{q}), '%')
ORDER BY group_id DESC LIMIT #{size} OFFSET #{offset}
